class ReconnectingWebSocket {
    constructor(url, options = {}) {
        this.url = url;
        this.retryDelay = options.retryDelay || 1000;   // start 1s
        this.maxRetryDelay = options.maxRetryDelay || 30000;  // max 30s
        this.connect();
    }

    connect() {
        this.stompClient = Stomp.over(new SockJS(this.url));
        this.stompClient.connect({}, this.onConnect, this.onError);
    }

    onConnect = (frame) => {
        console.log('WebSocket connected');
        this.retryDelay = 1000;  // reset backoff on successful connect

        // Re-subscribe after reconnect
        this.stompClient.subscribe('/user/queue/order-updates',
            msg => this.onMessage(JSON.parse(msg.body)));

        // Request missed events (see server-side implementation below)
        this.requestMissedEvents();
    }

    onError = (error) => {
        console.log(`Disconnected. Retrying in ${this.retryDelay}ms...`);
        setTimeout(() => this.connect(), this.retryDelay);
        this.retryDelay = Math.min(this.retryDelay * 2, this.maxRetryDelay); // exponential backoff
    }

    requestMissedEvents() {
        const lastSeen = localStorage.getItem('lastEventTimestamp');
        if (lastSeen) {
            // Ask server for events since last seen
            fetch(`/api/orders/events?since=${lastSeen}`).then(r => r.json())
                .then(events => events.forEach(e => this.onMessage(e)));
        }
    }
}
```

